import{_ as s,o as n,c as r,O as l}from"./chunks/framework.47655c42.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"product/scenarios.md","filePath":"product/scenarios.md","lastUpdated":1775995223000}'),i={name:"product/scenarios.md"};function c(e,a,t,p,d,o){return n(),r("div",null,a[0]||(a[0]=[l('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Scenarios</p><h1>应用场景</h1><div class="brand-hero__panel"><span class="brand-pill">Usage Thesis</span><strong>不是让 AI 多说一点，而是让任务真正落地。</strong><p>每个场景都围绕“入口、确认、执行、留痕、治理”这条主链路展开。</p></div><p class="brand-lead"> ExecGov 不是抽象概念站点，它解决的是 <strong>真实任务如何被 AI 安全调度执行</strong>。 场景越真实，这套平台的边界和价值就越清楚。 </p><div class="brand-chip-list"><span class="brand-chip">运营数据自动化</span><span class="brand-chip">脚本治理与运维</span><span class="brand-chip">私有化客户</span><span class="brand-chip">混合执行</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../contact.html#lead-form">沟通真实场景</a><a class="cta-button" href="./capabilities.html">查看核心能力</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // SCENARIO MAP</span><span>DOC 02</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">scenarioA</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;ops_automation_team&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">scenarioB</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;customer_delivery_project&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">scenarioC</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;free_entry&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;local_bridge&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;template_ops&#39;</span><span class="matrix-panel__punct">]</span></span></div><div class="matrix-panel__callout">SCENARIOS SHOULD MATCH REAL BUYING INTENT</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">delivery</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">ops</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">local_bridge</span></span></div></div></div></section><section class="brand-card"><p class="brand-kicker">Priority Segments</p><h2>当前最值得优先深耕的三类客户</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>电商 / 内容 / 运营数据自动化</h3><p>适合已经有抓取、清洗、报表、导入导出脚本，但入口分散、执行混乱、结果追踪困难的团队。</p></article><article class="brand-card brand-card--nested"><h3>技术团队脚本治理与自动化运维</h3><p>适合日志清理、巡检、批量处理、定时报表、脚本权限管理和执行审计这类场景。</p></article><article class="brand-card brand-card--nested"><h3>需要内网或私有化的小型正式客户</h3><p>适合对租户隔离、权限边界、内网环境和正式交付有明确要求，但又不想一开始就上重系统的客户。</p></article></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">01</p><h2>团队内部流程自动化</h2><ul class="brand-list"><li>已有 Python / 自动化脚本，但使用方式分散</li><li>希望把脚本收成统一入口，而不是每个人手工跑环境</li><li>需要执行可留痕、可确认、可审计</li><li>适合电商、内容、运营数据这类数据整理、批量处理和周期报表任务</li></ul></article><article class="brand-card"><p class="brand-kicker">02</p><h2>正式客户隔离交付</h2><ul class="brand-list"><li>一个客户一套隔离环境</li><li>平台方统一管理客户、模板、日志和公告</li><li>同一套底座持续复制到多个客户</li><li>重点是“租户边界清晰 + 平台能治理”，不是把所有客户混在一个后台里</li></ul></article><article class="brand-card"><p class="brand-kicker">03</p><h2>个人与小团队入口</h2><ul class="brand-list"><li>把本地脚本整理成可描述、可调用的能力</li><li>用统一入口展示和运行自己的工具</li><li>用 CLI 把本地脚本接入平台</li><li>既是体验入口，也是后续更深协作场景的升级入口</li></ul></article></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">04</p><h2>混合执行与本地接入</h2><ul class="brand-list"><li>任务涉及本地文件目录</li><li>依赖内网资源、私有数据源或本地网络环境</li><li>Web 端负责入口、规划、确认和留痕</li><li>本地环境与 CLI / Agent 负责真实执行</li></ul></article><article class="brand-card"><p class="brand-kicker">05</p><h2>超管治理与模板分发</h2><ul class="brand-list"><li>模板分发</li><li>公告投放</li><li>客户与租户治理</li><li>平台审计、版本回滚和运营台账</li></ul></article><article class="brand-card"><p class="brand-kicker">06</p><h2>脚本治理与自动化运维</h2><ul class="brand-list"><li>适合日志清理、巡检、批量处理和定时任务</li><li>强调脚本入口统一、人工确认和执行留痕</li><li>适合本地环境、本地脚本或内网资源受控调度</li><li>更贴近平台当前已经成熟的脚本优先能力边界</li></ul></article></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Boss View 01</p><h2>它到底帮团队省什么事</h2><p>把原本靠人手反复执行的脚本、数据处理和流程，收成一个统一入口。团队不需要再记一堆命令、找一堆脚本、问很多人。</p></article><article class="brand-card"><p class="brand-kicker">Boss View 02</p><h2>它为什么不会失控</h2><p>这套平台强调“权限边界 + 人工确认 + 执行留痕”。重点不是让 AI 自由发挥，而是让自动化真正可控。</p></article><article class="brand-card"><p class="brand-kicker">Boss View 03</p><h2>它为什么值得先继续投入</h2><p>价值不只是完成一次自动化，而是把零散脚本沉淀成可复用、可持续更新、可长期演进的能力底座。</p></article></section><section class="brand-card"><p class="brand-kicker">Future Scenarios</p><h2>长期可扩展的能力场景</h2><p>ExecGov 现在最成熟的是 Python 脚本场景，但这套底座后续也适合继续承接下面这些方向。这里强调的是平台演进空间，不代表今天已经全部做成标准产品。</p><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>企业接口自动化</h3><p>把短信、邮件、ERP、CRM、OA、Webhook 等系统接口纳入统一入口和审计链路。</p></article><article class="brand-card brand-card--nested"><h3>数据读写与同步</h3><p>把数据库读写、报表同步、仓库回写和主数据更新纳入标准化能力。</p></article><article class="brand-card brand-card--nested"><h3>标准文档生成</h3><p>把合同、报价单、周报、项目计划书和行业文书生成纳入模板化执行流程。</p></article><article class="brand-card brand-card--nested"><h3>审批流与工单流转</h3><p>把审批单发起、工单推进、流程节点触发和状态查询纳入受控动作。</p></article><article class="brand-card brand-card--nested"><h3>专用 AI 能力服务</h3><p>把文档解析、OCR、语音识别、图片生成等专用模型服务接入统一治理链路。</p></article><article class="brand-card brand-card--nested"><h3>运维与告警联动</h3><p>把巡检、备份、日志清理、告警通知、服务状态检查等动作继续标准化。</p></article></div></section><section class="brand-card"><p class="brand-kicker">How To Judge Fit</p><h2>高匹配度场景判断</h2><div class="brand-link-grid"><a class="brand-link-card" href="./capabilities.html"><span>Capability Fit</span><strong>你已经有脚本，但没有统一治理</strong><p>核心能力页用于确认多租户、执行闭环和模板治理是否契合。</p></a><a class="brand-link-card" href="./deployment.html"><span>Deployment Fit</span><strong>你担心本地环境、内网或混合执行</strong><p>部署方式页说明平台如何把控制面和执行端拆开治理。</p></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead Fit</span><strong>你想直接拿真实场景来沟通</strong><p>可直接提交线索，先判断该继续走标准团队版还是企业交付沟通。</p></a><a class="brand-link-card" href="./cli.html"><span>CLI Fit</span><strong>你手里已经有本地脚本，想先低成本接起来</strong><p>CLI 指引用于确认当前登录、注册、执行和 Agent 骨架是否符合落地方式。</p></a></div></section><section class="brand-card"><p class="brand-kicker">Scenario To Delivery</p><h2>场景确认后的关键资料</h2><div class="brand-link-grid brand-link-grid--three"><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>场景依赖文件输入和结果产物</strong><p>任务涉及 Excel、CSV、压缩包或其它输入文件并需要结果文件时，文件链路说明更直接。</p></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>场景最终如何变成交付物</strong><p>推进项目时，除了证明场景成立，还需要明确客户最终拿到什么入口、什么说明和什么结果物。</p></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>场景接入前要准备哪些资料</strong><p>已有真实脚本能力和样例时，先把脚本目录、README、依赖和风险边界准备齐，推进会更顺畅。</p></a></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>场景确认后，建议同时查看交付与接入资料</h2><p class="brand-lead">场景页适合先判断项目是否成立；进入推进阶段后，更关键的是文件链路、交付物和接入准备。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./customer-flow.html"><span>Flow</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>文件上传 / 结果下载</strong></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>交付物 / 文档入口</strong></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>客户接入准备清单</strong></a></div></div></section></div>',1)]))}const h=s(i,[["render",c]]);export{_ as __pageData,h as default};
